			"type": "wiki-page-name",
                        "suggested": true
		},
		"2": {
			"label": "Optional additional article to link (2)",
			"description": "Optional additional article to link",
			"type": "wiki-page-name"
		},
		"3": {
			"label": "Optional additional article to link (3)",
