	"params": {
		"1": {
			"label": "Name of article",
			"description": "Name of article that you want to link to",
			"type": "wiki-page-name",
            "suggested": true
		},
		"2": {
			"label": "Optional additional article to link",
			"description": "Optional additional article to link",
			"type": "wiki-page-name"
		},
		"3": {
			"label": "Optional additional article to link",
			"description": "Optional additional article to link",
			"type": "wiki-page-name"
		},
		"4": {
			"label": "Optional additional article to link",
